  ('social-worker-moex-07620', 'social-worker', 'social-worker-moex-099-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '「三明治」時代是指人生發展那一階段？', '["成年前期", "中年期", "成人晚期", "老年期"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "998532e9120f", "answer_pdf_sha1": "5c1028fd7619", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "600", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 37, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07621', 'social-worker', 'social-worker-moex-099-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', 'Minuchin & Fishman（1981）將家庭「形狀（Shapes）」分門別類，下列描述何者不正確？', '["兩人組合的家庭形式", "一條鞭法家庭形式", "漂動家庭", "單一親職責任家庭"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "998532e9120f", "answer_pdf_sha1": "5c1028fd7619", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "600", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 38, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07622', 'social-worker', 'social-worker-moex-099-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列何者是有關年長者的承諾與統合，重新調整他們的精力以因應失去的角色、活動及能力的理論？', '["角色喪失理論", "角色能力理論", "活動理論", "角色整合理論"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "998532e9120f", "answer_pdf_sha1": "5c1028fd7619", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "600", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 39, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07623', 'social-worker', 'social-worker-moex-099-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '所謂「社會參考」是指：', '["幼兒會觀察周邊人行為反應線索，決定自己的行動", "父母會參考幼兒的行為，決定自己的態度", "社會大眾會受到性別刻板印象的影響，決定如何對待幼兒", "青少年在道德成規期會參考利他原則，決定自己的行為"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "998532e9120f", "answer_pdf_sha1": "5c1028fd7619", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "600", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 40, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07624', 'social-worker', 'social-worker-moex-099-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '年第一次專門職業及技術人員高等考試社會工作師考試試題 類       科：社會工作師 甲、作文部分：（60分） 請以藍、黑色鋼筆或原子筆在申論試卷上作答，於本試題上作答者，不予計分。 工作的目標與動力 乙、測驗部分：（40分）                                代號：2902 共20題，每題2分，須用2Ｂ鉛筆在試卡上依題號清楚劃記，於本試題或申論試卷上作答者，不予計分。 ㉑下列文句「」內字義相同的選項是：', '["一鼓「作」氣，再而衰，三而竭（《左傳‧莊公十年》）∕述而不「作」，信 而好古（《論語‧述而》）", "宋人有善為不手之藥者，世世以洴澼絖為「事」（《莊子‧逍遙游》）∕天 下多「事」，吏不能紀（《新書‧過秦下》）", "公孫鞅之治秦也，設告相「坐」而責其實（《韓非子‧定法》）∕「坐」井而 觀天，曰天小者，非天小也（韓愈〈原道〉）", "與其從辟人之士也，豈若從辟「世」之士哉（《論語‧微子》）∕千歲厭「世」， 去而上僊；乘彼白雲，至於帝鄉（《莊子‧天地》） ㉒下列各組文句引號內的詞語，意義相同的是："]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "ab2db3cf47a9", "answer_pdf_sha1": "778e5597f784", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 99, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07625', 'social-worker', 'social-worker-moex-099-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「木末芙蓉花，山中發紅萼。澗戶寂無人，紛紛開且落。」（王維〈辛夷塢〉）下列成語，何者可以詮 釋此詩意境？', '["出水芙蓉", "一枝獨秀", "空谷幽蘭", "名花傾國"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "c67fbcca8028", "answer_pdf_sha1": "54154d8d65c4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 1, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07626', 'social-worker', 'social-worker-moex-099-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '有關信封受信人的寫法，下列何者為錯誤的選項？', '["張學富主任  鈞啟", "張主任學富  鈞啟", "張學富  主任（右偏）  鈞啟", "張主任  學富（右偏）  鈞啟"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "c67fbcca8028", "answer_pdf_sha1": "54154d8d65c4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 2, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07627', 'social-worker', 'social-worker-moex-099-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「王子犯法，與庶民同罪」，不論古今，人們對政令法律要求的都是期待上下一律的公正公平，下列敘 述並不包含此種精神的選項是：', '["法不阿貴；繩不撓曲（《韓非子．有度》）", "誅不避貴，賞不遺賤（《晏子春秋．內篇問上》）", "厲法禁，自大臣始，則小臣不犯矣（蘇軾《策刑第六》）", "明刑而不濫乎所恨，審賞而不加乎附己（葛洪《抱朴子．臣節》）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "c67fbcca8028", "answer_pdf_sha1": "54154d8d65c4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 3, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07628', 'social-worker', 'social-worker-moex-099-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '子曰：「富而可求也，雖執鞭之士，吾亦為之；如不可求，從吾所好。」（《論語．述而》）下列闡釋 最切合上文主旨的選項是：', '["追求財富，須謹守原則", "貧富貴賤，原各有命定", "執鞭之士，有致富之日", "鐘鼎山林，應相互尊重"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "c67fbcca8028", "answer_pdf_sha1": "54154d8d65c4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 4, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07629', 'social-worker', 'social-worker-moex-099-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '語言文字的使用往往會影響讀者的觀感和判斷，以美國對婦女墮胎事件的爭議為例，支持墮胎者主張 「選擇的權利」，反對者則高呼「生存的權利」，對同一事件雙方說法迥然不同，最主要是因為下列何 種原因：', '["支持者只考慮人權的問題，反對者則只顧及道德人性", "支持者使用的語言太激進，反對者使用的語言比較保守", "支持者的主張是從婦女的立場而言，而反對者的主張則從嬰兒的立場出發", "「選擇」和「生存」兩詞語意正好相反對立，正反雙方藉以表達不同立場"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "c67fbcca8028", "answer_pdf_sha1": "54154d8d65c4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 5, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
